/**
 * Generated by `createschema miniapp.B2CApp 'name:Text'`
 */

const isEqual = require('lodash/isEqual')
const pick = require('lodash/pick')

const { userIsAdminOrIsSupport } = require('@open-condo/keystone/access')
const { historical, versioned, uuided, tracked, softDeleted, dvAndSender, analytical } = require('@open-condo/keystone/plugins')
const { composeNonResolveInputHook } = require('@open-condo/keystone/plugins/utils')
const { GQLListSchema } = require('@open-condo/keystone/schema')

const { getSharedConstraintsValidator } = require('@dev-portal-api/domains/common/serverSchema/constraints')
const {
    getFileMetaAfterChange,
    FileAdapter,
    getMimeTypesValidator,
} = require('@dev-portal-api/domains/common/utils/files')
const { B2C_APP_TYPES, B2C_APP_CORDOVA_TYPE } = require('@dev-portal-api/domains/miniapp/constants/b2c')
const { DEV_ENVIRONMENT, PROD_ENVIRONMENT } = require('@dev-portal-api/domains/miniapp/constants/publishing')
const { exportable } = require('@dev-portal-api/domains/miniapp/plugins/exportable')
const { publishB2CApp: publishB2CAppTask } = require('@dev-portal-api/domains/miniapp/tasks/publishB2CApp')
const { canReadAppSchemas, canManageAppSchemas } = require('@dev-portal-api/domains/miniapp/utils/serverSchema/access')

const { getEnvironmentalFields, getEnvironmentalFieldName } = require('./fields/environmental')

const LOGO_FILE_ADAPTER = new FileAdapter('B2CApps/logos', true)
const logoMetaAfterChange = getFileMetaAfterChange(LOGO_FILE_ADAPTER, 'logo')

const COMMON_CHANGEABLE_FIELDS = ['name', 'type', 'logo', 'developer']
const DEV_CHANGEABLE_FIELDS = [...COMMON_CHANGEABLE_FIELDS, getEnvironmentalFieldName(DEV_ENVIRONMENT, 'webTransformEnabled')]
const PROD_CHANGEABLE_FIELDS = [...COMMON_CHANGEABLE_FIELDS, getEnvironmentalFieldName(PROD_ENVIRONMENT, 'webTransformEnabled')]

async function autoPublishAfterChange ({ updatedItem, existingItem }) {
    if (!isEqual(pick(updatedItem, DEV_CHANGEABLE_FIELDS), pick(existingItem, DEV_CHANGEABLE_FIELDS))) {
        await publishB2CAppTask.delay(updatedItem.id, DEV_ENVIRONMENT)
    }
    if (!isEqual(pick(updatedItem, PROD_CHANGEABLE_FIELDS), pick(existingItem, PROD_CHANGEABLE_FIELDS))) {
        await publishB2CAppTask.delay(updatedItem.id, PROD_ENVIRONMENT)
    }
}

const B2CApp = new GQLListSchema('B2CApp', {
    schemaDoc: 'B2C application',
    fields: {
        name: {
            schemaDoc: 'Name of application',
            type: 'Text',
            isRequired: true,
        },
        type: {
            schemaDoc: 'Type of application',
            type: 'Select',
            dataType: 'string',
            isRequired: true,
            options: B2C_APP_TYPES,
            defaultValue: B2C_APP_CORDOVA_TYPE,
            access: {
                read: true,
                create: true,
                update: userIsAdminOrIsSupport,
            },
        },
        logo: {
            schemaDoc: 'Icon of application',
            type: 'File',
            isRequired: false,
            adapter: LOGO_FILE_ADAPTER,
            hooks: {
                validateInput: getMimeTypesValidator({ allowedTypes: ['image/png'] }),
            },
        },
        developer: {
            schemaDoc: 'Developer company name which will be exported. If not specified, creator name will be taken',
            type: 'Text',
            isRequired: false,
        },
        ...getEnvironmentalFields('webTransformEnabled', {
            schemaDoc:
                'Enables automatic transformation from native environments to web ' +
                'and allows automatic web-hosting on publish for {environment} environment',
            type: 'Checkbox',
            isRequired: true,
            defaultValue: false,
        }),
        ...getEnvironmentalFields('publishedAt', {
            schemaDoc: 'The last time a mini-app was published on the {environment} environment',
            type: 'DateTimeUtc',
            kmigratorOptions: { db_index: true },
            access: {
                read: true,
                create: false,
                // NOTE: function used to make it appear in B2CAppUpdateInput
                update: () => false,
            },
        }),
    },
    hooks: {
        validateInput: getSharedConstraintsValidator(['B2BApp']),
        afterChange: composeNonResolveInputHook(logoMetaAfterChange, autoPublishAfterChange),
    },
    plugins: [uuided(), versioned(), tracked(), softDeleted(), dvAndSender(), exportable(), historical(), analytical()],
    access: {
        read: canReadAppSchemas,
        create: canManageAppSchemas,
        update: canManageAppSchemas,
        delete: false,
        auth: true,
    },
})

module.exports = {
    B2CApp,
}
